import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct

app = Flask(__name__)

# Configure an Ethereum provider URL
# You can use Infura, Alchemy, or a local Ganache instance
# It's good practice to load this from environment variables
ETHEREUM_PROVIDER_URL = os.environ.get("ETHEREUM_PROVIDER_URL", "https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID")

# Initialize web3
w3 = Web3(Web3.HTTPProvider(ETHEREUM_PROVIDER_URL))

# Ensure connection to Ethereum node
if not w3.is_connected():
    print(f"Failed to connect to Ethereum provider at {ETHEREUM_PROVIDER_URL}")
    print("Please check your ETHERUM_PROVIDER_URL or Infura Project ID.")
    exit(1)

@app.route('/auth/signature', methods=['POST'])
def verify_signature():
    data = request.get_json()

    if not data:
        return jsonify({"error": "No input data provided"}), 400

    message = data.get('message')
    signature = data.get('signature')
    expected_address = data.get('address') # Optional: client can send expected address

    if not all([message, signature]):
        return jsonify({"error": "Missing 'message' or 'signature'"}), 400

    try:
        # 1. Encode the message as per EIP-191
        encoded_message = encode_defunct(text=message)

        # 2. Recover the address from the signature
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)

        # 3. Compare with the expected address (if provided)
        # It's crucial for the client to trust the message they signed.
        # The recovered_address is the source of truth.
        if expected_address:
            if recovered_address.lower() == expected_address.lower():
                return jsonify({
                    "authenticated": True,
                    "recovered_address": recovered_address,
                    "message": "Signature verified successfully for the provided address."
                }), 200
            else:
                return jsonify({
                    "authenticated": False,
                    "recovered_address": recovered_address,
                    "message": "Signature is valid but does not match the provided address."
                }), 401
        else:
            # If no expected_address is provided, just return the recovered address
            # The client (or subsequent backend logic) would then check if this address
            # is registered or authorized.
            return jsonify({
                "authenticated": True, # Technically, the signature is valid
                "recovered_address": recovered_address,
                "message": "Signature verified successfully. Recovered address returned."
            }), 200

    except ValueError as e:
        return jsonify({"error": f"Invalid signature or message format: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": f"An unexpected error occurred: {str(e)}"}), 500

if __name__ == '__main__':
    # For development, you might want to run with debug=True
    # For production, use a production-ready WSGI server like Gunicorn
    app.run(host='0.0.0.0', port=5000)